#include <bits/stdc++.h>
using namespace std;

int q;
long long l,r;

int main(){
    scanf("%d",&q);
    while(q--){
        scanf("%lld%lld",&l,&r);
        long long tmp=l/9*9;
        l-=tmp,r-=tmp;
        r-=(r-l)/9*9;
        printf("%d\n",(r+l)*(r-l+1)/2%9);
    }
    return 0;
}
